-- Livin' — Supabase schema + seed.
-- Run this once in the Supabase SQL Editor (Dashboard → SQL Editor → New query → paste → Run).
-- Safe to re-run: it uses IF NOT EXISTS on the table and ON CONFLICT for the seed.

-- 1. Table: one row per collection. The `data` column is the entire collection
--    JSON (same shape as the old content/collections/<slug>.json files).
create table if not exists public.collections (
  slug text primary key,
  data jsonb not null,
  updated_at timestamptz not null default now()
);

-- Bump updated_at automatically on every UPDATE.
create or replace function public.set_updated_at() returns trigger
language plpgsql as $$
begin
  new.updated_at := now();
  return new;
end;
$$;

drop trigger if exists collections_set_updated_at on public.collections;
create trigger collections_set_updated_at
before update on public.collections
for each row execute function public.set_updated_at();

-- 2. Row-Level Security: public can READ, only authenticated users can WRITE.
--    Server code that uses the service_role key bypasses RLS entirely.
alter table public.collections enable row level security;

drop policy if exists "public read collections" on public.collections;
create policy "public read collections"
on public.collections
for select
to anon, authenticated
using (true);

drop policy if exists "authenticated write collections" on public.collections;
create policy "authenticated write collections"
on public.collections
for all
to authenticated
using (true)
with check (true);

